+        }
+
+        let close_braces = trimmed.chars().filter(|ch| *ch == '}').count();
+        brace_depth += open_braces;
+        brace_depth = brace_depth.saturating_sub(close_braces);
+
+        while scope_stack
+            .last()
+            .is_some_and(|frame| brace_depth < frame.depth)
+        {
+            scope_stack.pop();
+        }
